import os, base64, subprocess, sys, shutil
BASE = os.path.join(os.getcwd(), 'orschell-ecommerce')
os.makedirs(BASE, exist_ok=True)
FILES = {
  'package.json': '',
  'src/db/database.ts': '',
  'src/index.ts': '',
  'src/middleware/auth.ts': '',
  'src/routes/admin.ts': '',
  'src/routes/auth.ts': '',
  'src/routes/cart.ts': '',
  'src/routes/categories.ts': '',
  'src/routes/orders.ts': '',
  'src/routes/products.ts': '',
  'src/types/index.ts': '',
  'tsconfig.json': '',
}

for rel, b64content in FILES.items():
    path = os.path.join(BASE, rel.replace('/', os.sep))
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'wb') as f:
        f.write(base64.b64decode(b64content))
    print(f'wrote {rel}')

# On Windows, npm is npm.cmd (a batch script, not a binary)
npm_cmd = 'npm.cmd' if sys.platform == 'win32' else 'npm'

print('[build] npm install...')
r = subprocess.run([npm_cmd, 'install'], cwd=BASE, capture_output=True, text=True, shell=False)
print(r.stdout[-3000:] if r.stdout else '')
print(r.stderr[-1000:] if r.stderr else '')
if r.returncode != 0:
    print('npm install FAILED', r.returncode)
    sys.exit(r.returncode)

tsc_path = os.path.join(BASE, 'node_modules', '.bin', 'tsc.cmd' if sys.platform == 'win32' else 'tsc')
if not os.path.exists(tsc_path):
    tsc_path = os.path.join(BASE, 'node_modules', '.bin', 'tsc')

print(f'[build] tsc at {tsc_path}...')
r2 = subprocess.run([tsc_path, '--build'], cwd=BASE, capture_output=True, text=True, shell=False)
print(r2.stdout[-3000:] if r2.stdout else '')
print(r2.stderr[-3000:] if r2.stderr else '')
if r2.returncode != 0:
    print('tsc FAILED', r2.returncode)
    sys.exit(r2.returncode)

print('[build] SUCCESS - dist/ created')
